service cloud.firestore {
  match /databases/{database}/documents {
    match /users/{uid} {
      allow read, write: if request.auth != null
                         && request.auth.uid == uid;
    }
  }
}

// authErrors.js
export function authMessage(code) {
  switch (code) {
    case 'auth/email-already-in-use': return "that email's already taken";
    case 'auth/invalid-credential':
    case 'auth/wrong-password':
    case 'auth/user-not-found':       return 'wrong email or password, try again';
    case 'auth/network-request-failed': return 'no internet? check your connection';
    default: return 'something broke, try again';
  }
}
